export async function fetchAdminStats() {
  const defaultStats = { totalUsers: 0, totalEntries: 0, totalHistory: 0, recentActivity: [], users: [], error: null };
  if (!CONFIG.SUPABASE_URL || CONFIG.SUPABASE_URL.includes('placeholder')) {
    return { ...defaultStats, error: 'Configuration Missing: SUPABASE_URL is not set.' };
  }

  try {
    // Fetch counts individually to prevent one missing table from breaking everything
    const [profilesRes, entriesRes, historyRes, recentRes, userList] = await Promise.allSettled([
      supabase.from('lex_profiles').select('*', { count: 'exact', head: true }),
      supabase.from('lex_entries').select('*', { count: 'exact', head: true }),
      supabase.from('lex_user_history').select('*', { count: 'exact', head: true }),
      supabase.from('lex_entries').select('term, source_lang, target_lang, created_at').order('created_at', { ascending: false }).limit(10),
      fetchAdminUsers()
    ]);

    const stats = { ...defaultStats };

    if (profilesRes.status === 'fulfilled' && !profilesRes.value.error) {
      stats.totalUsers = profilesRes.value.count || 0;
    }
    if (entriesRes.status === 'fulfilled' && !entriesRes.value.error) {
      stats.totalEntries = entriesRes.value.count || 0;
    }
    if (historyRes.status === 'fulfilled' && !historyRes.value.error) {
      stats.totalHistory = historyRes.value.count || 0;
    }
    if (recentRes.status === 'fulfilled' && !recentRes.value.error) {
      stats.recentActivity = recentRes.value.data || [];
    }
    if (userList.status === 'fulfilled') {
      stats.users = userList.value;
    }

    // Check if everything failed
    const allFailed = [profilesRes, entriesRes, historyRes].every(r => r.status === 'rejected' || (r.status === 'fulfilled' && r.value.error));
    if (allFailed) {
      stats.error = "Connection established, but tables were not found or access was denied.";
    }

    return stats;
  } catch (err: any) {
    return { ...defaultStats, error: err.message || "Unknown database connection failure." };
  }
}

