import React, { useEffect, useState } from 'react';
import { fetchAdminStats, saveGlobalEntry, checkConnection } from '../services/supabase';
import { translateWordCore, enrichLexicalEntry } from '../services/gemini';
import { triggerHaptic } from '../services/telegram';
import { Language } from '../types';

interface Stats {
  totalUsers: number;
  totalEntries: number;
  totalHistory: number;
  recentActivity: any[];
  users: any[];
  error?: string | null;
}

interface LogEntry {
  term: string;
  status: 'queued' | 'processing' | 'enriched' | 'completed' | 'error';
  message?: string;
}

const LANGUAGES_LIST: Language[] = ['German', 'Uzbek', 'English', 'Russian', 'Arabic'];

const AdminPanel: React.FC = () => {
  const [stats, setStats] = useState<Stats | null>(null);
  const [loading, setLoading] = useState(true);
  const [actionLoading, setActionLoading] = useState<string | null>(null);
  const [dbStatus, setDbStatus] = useState<'connected' | 'error' | 'checking'>('checking');

  // Bulk Inscription State
  const [bulkInput, setBulkInput] = useState('');
  const [sourceLang, setSourceLang] = useState<Language>('German');
  const [targetLang, setTargetLang] = useState<Language>('Uzbek');
  const [isProcessingBatch, setIsProcessingBatch] = useState(false);
  const [batchLogs, setBatchLogs] = useState<LogEntry[]>([]);
  const [currentProgress, setCurrentProgress] = useState(0);

  const loadStats = async () => {
    setLoading(true);
    setDbStatus('checking');

    const isConnected = await checkConnection();
    setDbStatus(isConnected ? 'connected' : 'error');

    const data = await fetchAdminStats();
    setStats(data as Stats);
    setLoading(false);
  };

  const handlePurgeCache = () => {
    setActionLoading('purge');
    triggerHaptic('heavy');
    setTimeout(() => {
      localStorage.removeItem('lexHistory');
      setActionLoading(null);
      alert("Local Archive Purged. System will resync on next reload.");
    }, 1500);
  };

  const handleGlobalSync = () => {
    setActionLoading('sync');
    triggerHaptic('success');
    loadStats().then(() => {
      setActionLoading(null);
    });
  };

  const processBulkInscription = async () => {
    const terms = bulkInput
      .split(/[\n,]+/)
      .map(t => t.trim())
      .filter(t => t.length > 0);

    if (terms.length === 0) return;

    setIsProcessingBatch(true);
    setCurrentProgress(0);
    setBatchLogs(terms.map(t => ({ term: t, status: 'queued' })));
    triggerHaptic('medium');

    for (let i = 0; i < terms.length; i++) {
      const term = terms[i];

      setBatchLogs(prev => prev.map((l, idx) => idx === i ? { ...l, status: 'processing' } : l));

      try {
        const coreEntry = await translateWordCore(term, sourceLang, targetLang);
        setBatchLogs(prev => prev.map((l, idx) => idx === i ? { ...l, status: 'enriched' } : l));
        const enrichment = await enrichLexicalEntry(coreEntry);
        const fullEntry = { ...coreEntry, ...enrichment };
        await saveGlobalEntry(fullEntry);
        setBatchLogs(prev => prev.map((l, idx) => idx === i ? { ...l, status: 'completed' } : l));
      } catch (err: any) {
        console.error(`Failed to inscribe ${term}:`, err);
        setBatchLogs(prev => prev.map((l, idx) => idx === i ? { ...l, status: 'error', message: err.message } : l));
      }

      setCurrentProgress(((i + 1) / terms.length) * 100);
    }

    setIsProcessingBatch(false);
    triggerHaptic('success');
    loadStats();
  };

  useEffect(() => {
    loadStats();
  }, []);

  if (loading) {
    return (
      <div className="flex flex-col items-center justify-center py-40">
        <div className="w-16 h-16 border-[4px] border-[#7c1a1a] border-t-transparent rounded-full animate-spin mb-8" />
        <p className="serif text-2xl italic text-stone-300">Summoning the Ledger...</p>
      </div>
    );
  }

  return (
    <div className="max-w-7xl mx-auto py-12 animate-in fade-in duration-700">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-end mb-16 gap-8">
        <div className="border-l-[4px] border-[#7c1a1a] pl-8">
          <div className="flex items-center gap-4 mb-2">
            <h1 className="text-6xl serif font-black text-stone-900 lowercase tracking-tighter">The Curator's Ledger</h1>
            <div className={`w-3 h-3 rounded-full mt-2 ${dbStatus === 'connected' ? 'bg-green-500 shadow-[0_0_8px_rgba(34,197,94,0.6)]' : 'bg-red-500 animate-pulse'}`} title={dbStatus === 'connected' ? 'Archive Connected' : 'Connection Failure'}></div>
          </div>
          <p className="text-[10px] uppercase tracking-[0.5em] text-stone-400 font-black">Administrative Overview & System Health</p>
        </div>

        <div className="flex items-center gap-4">
          <button 
            onClick={handleGlobalSync}
            disabled={!!actionLoading}
            className="px-6 py-3 bg-stone-900 text-white text-[9px] uppercase tracking-[0.3em] font-black hover:bg-stone-800 transition-all rounded-sm flex items-center gap-3 disabled:opacity-50"
          >
            {actionLoading === 'sync' ? <div className="w-3 h-3 border-2 border-white/20 border-t-white rounded-full animate-spin" /> : <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><path d="M21 12a9 9 0 0 0-9-9 9.75 9.75 0 0 0-6.74 2.74L3 8"/><path d="M3 3v5h5"/><path d="M3 12a9 9 0 0 0 9 9 9.75 9.75 0 0 0 6.74-2.74L21 16"/><path d="M16 16h5v5"/></svg>}
            Global Sync
          </button>
          <button 
            onClick={handlePurgeCache}
            disabled={!!actionLoading}
            className="px-6 py-3 border border-stone-200 text-stone-400 text-[9px] uppercase tracking-[0.3em] font-black hover:text-[#7c1a1a] hover:border-[#7c1a1a] transition-all rounded-sm flex items-center gap-3 disabled:opacity-50"
          >
            {actionLoading === 'purge' ? <div className="w-3 h-3 border-2 border-[#7c1a1a]/20 border-t-[#7c1a1a] rounded-full animate-spin" /> : <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><path d="M3 6h18"/><path d="M19 6v14c0 1-1 2-2 2H7c-1 0-2-1-2-2V6"/><path d="M8 6V4c0-1 1-2 2-2h4c1 0 2 1 2 2v2"/></svg>}
            Purge Local
          </button>
        </div>
      </div>

      {stats?.error && (
        <div className="mb-12 bg-red-50 border border-red-100 p-8 rounded-sm animate-in shake duration-500">
           <div className="flex items-start gap-6">
              <div className="p-3 bg-red-100 rounded-full text-red-600">
                <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><circle cx="12" cy="12" r="10"/><line x1="12" y1="8" x2="12" y2="12"/><line x1="12" y1="16" x2="12.01" y2="16"/></svg>
