import { createClient } from '@supabase/supabase-js';
import { LexicalEntry, UserProfile, Language } from '../types';
import { CONFIG } from '../constants';

// Supabase requires a valid URL format and a non-empty key to initialize without throwing.
const supabaseUrl = CONFIG.SUPABASE_URL || 'https://placeholder-project.supabase.co';
const supabaseKey = CONFIG.SUPABASE_ANON_KEY || 'empty-key-placeholder';

export const supabase = createClient(supabaseUrl, supabaseKey);

const suggestionCache = new Map<string, string[]>();

const handleSupabaseError = (error: any, tableName: string) => {
  if (!CONFIG.SUPABASE_URL || CONFIG.SUPABASE_URL.includes('placeholder')) {
    return true; 
  }
  // Log specific technical details for the developer but return true to allow the UI to handle it gracefully
  if (error?.code === 'PGRST204' || error?.code === 'PGRST205' || error?.status === 404 || error?.message?.includes('does not exist')) {
    console.warn(`Table [${tableName}] missing or unreachable.`);
    return true; 
  }
  if (error) console.error(`Supabase Error [${tableName}]:`, error);
  return false;
};

export async function checkConnection(): Promise<boolean> {
  if (!CONFIG.SUPABASE_URL || CONFIG.SUPABASE_URL.includes('placeholder')) return false;
  try {
    const { error } = await supabase.from('lex_profiles').select('count', { count: 'exact', head: true }).limit(1);
    return !error;
  } catch {
    return false;
  }
}

export async function fetchAdminUsers() {
  if (!CONFIG.SUPABASE_URL) return [];
  try {
    const { data: profileData, error: profileError } = await supabase
      .from('lex_profiles')
      .select('username, telegram_id, updated_at')
      .order('updated_at', { ascending: false })
      .limit(50);

    if (profileError) {
      handleSupabaseError(profileError, 'lex_profiles');
      return [];
    }

    return (profileData || []).map(p => ({
      username: p.username,
      first_name: p.username || 'Scholar',
      created_at: p.updated_at
    }));
  } catch (err) {
    return [];
  }
}

export async function fetchAdminStats() {
  const defaultStats = { totalUsers: 0, totalEntries: 0, totalHistory: 0, recentActivity: [], users: [], error: null };

  if (!CONFIG.SUPABASE_URL || CONFIG.SUPABASE_URL.includes('placeholder')) {
    return { ...defaultStats, error: 'SUPABASE_URL environment variable is missing or invalid.' };
  }

  try {
    // We use allSettled to ensure that even if one table (e.g. history) is missing, the others still load.
    const [profilesRes, entriesRes, historyRes, recentRes, userListRes] = await Promise.allSettled([
      supabase.from('lex_profiles').select('*', { count: 'exact', head: true }),
      supabase.from('lex_entries').select('*', { count: 'exact', head: true }),
      supabase.from('lex_user_history').select('*', { count: 'exact', head: true }),
      supabase.from('lex_entries').select('term, source_lang, target_lang, created_at').order('created_at', { ascending: false }).limit(10),
      fetchAdminUsers()
    ]);

    const stats: any = { ...defaultStats };

    if (profilesRes.status === 'fulfilled' && !profilesRes.value.error) {
      stats.totalUsers = profilesRes.value.count || 0;
    }
    if (entriesRes.status === 'fulfilled' && !entriesRes.value.error) {
      stats.totalEntries = entriesRes.value.count || 0;
    }
    if (historyRes.status === 'fulfilled' && !historyRes.value.error) {
      stats.totalHistory = historyRes.value.count || 0;
    }
    if (recentRes.status === 'fulfilled' && !recentRes.value.error) {
      stats.recentActivity = recentRes.value.data || [];
    }
    if (userListRes.status === 'fulfilled') {
      stats.users = userListRes.value;
    }

    // Diagnostic check: if all core counts failed, report a structural error
    const countErrors = [profilesRes, entriesRes, historyRes].filter(r => r.status === 'rejected' || (r.status === 'fulfilled' && r.value.error));
    if (countErrors.length === 3) {
      stats.error = "All database tables are unreachable. Please verify Supabase connection and schema.";
    }

    return stats;
  } catch (err: any) {
    return { ...defaultStats, error: err.message || "Unknown retrieval failure." };
  }
}

export async function fetchSuggestions(query: string, sourceLang: Language): Promise<string[]> {
  if (!CONFIG.SUPABASE_URL) return [];
  const cleanQuery = query.toLowerCase().trim();
  if (cleanQuery.length < 2) return [];

  const cacheKey = `${sourceLang}:${cleanQuery}`;
  if (suggestionCache.has(cacheKey)) return suggestionCache.get(cacheKey)!;

  try {
    const { data, error } = await supabase
      .from('lex_entries')
      .select('term')
      .eq('source_lang', sourceLang)
      .ilike('normalized_term', `${cleanQuery}%`)
      .limit(8);

    if (error) {
      handleSupabaseError(error, 'lex_entries');
      return [];
    }

    const results: string[] = Array.from(new Set((data?.map(d => (d as any).term) || []).filter((t): t is string => typeof t === 'string' && !!t)));
    suggestionCache.set(cacheKey, results);
    return results;
  } catch {
    return [];
  }
}

export async function fetchGlobalEntry(normalizedTerm: string, sourceLang: Language, targetLang: Language): Promise<LexicalEntry | null> {
  if (!CONFIG.SUPABASE_URL) return null;
  try {
    const { data, error } = await supabase
      .from('lex_entries')
      .select('entry_data')
      .eq('normalized_term', normalizedTerm)
      .eq('source_lang', sourceLang)
      .eq('target_lang', targetLang)
      .maybeSingle();

    if (error) return null;
    return (data?.entry_data as LexicalEntry) || null;
  } catch {
    return null;
  }
}

export async function saveGlobalEntry(entry: LexicalEntry) {
  if (!CONFIG.SUPABASE_URL) return;
  try {
    await supabase.from('lex_entries').upsert({
      term: entry.term,
      normalized_term: entry.normalizedTerm,
      source_lang: entry.sourceLang,
      target_lang: entry.targetLang,
      entry_data: entry,
      created_at: new Date().toISOString()
    }, { onConflict: 'normalized_term, source_lang, target_lang' });
  } catch {}
}

export async function fetchProfile(telegramId: number): Promise<UserProfile | null> {
  if (!CONFIG.SUPABASE_URL) return null;
  try {
    const { data, error } = await supabase.from('lex_profiles').select('profile_data').eq('telegram_id', telegramId).maybeSingle();
    if (error) return null;
    return (data?.profile_data as UserProfile) || null;
  } catch {
    return null;
  }
}

export async function fetchUserHistory(telegramId: number): Promise<LexicalEntry[]> {
  if (!CONFIG.SUPABASE_URL) return [];
  try {
    const { data, error } = await supabase.from('lex_user_history').select('entry_data').eq('telegram_id', telegramId).order('created_at', { ascending: false }).limit(50);
    if (error) return [];
    return data?.map(d => d.entry_data as LexicalEntry) || [];
  } catch {
    return [];
  }
}

export async function saveUserHistoryEntry(telegramId: number, entry: LexicalEntry) {
  if (!CONFIG.SUPABASE_URL) return;
  try {
    await supabase.from('lex_user_history').upsert({
      telegram_id: telegramId,
      entry_id: entry.id,
      entry_data: entry,
      created_at: new Date().toISOString()
    }, { onConflict: 'telegram_id, entry_id' });
  } catch {}
}

export async function upsertProfile(profile: UserProfile) {
  if (!CONFIG.SUPABASE_URL || !profile.telegramId) return;
  try {
    // Secondary identity table (silent failure okay)
    supabase.from('users').upsert({
      telegram_id: profile.telegramId,
      username: profile.username || 'Scholar',
      first_name: profile.firstName || '',
      last_name: profile.lastName || '',
      updated_at: new Date().toISOString()
    }, { onConflict: 'telegram_id' }).then(({ error }) => {
      if (error) handleSupabaseError(error, 'users');
    });

    // Primary profile table
    const { error } = await supabase.from('lex_profiles').upsert({ 
      telegram_id: profile.telegramId,
      username: profile.username || 'Scholar',
      profile_data: profile,
      updated_at: new Date().toISOString() 
    }, { onConflict: 'telegram_id' });

    if (error) handleSupabaseError(error, 'lex_profiles');
  } catch {}
}

import React, { useEffect, useState } from 'react';
import { fetchAdminStats, saveGlobalEntry, checkConnection } from '../services/supabase';
import { translateWordCore, enrichLexicalEntry } from '../services/gemini';
import { triggerHaptic } from '../services/telegram';
import { Language } from '../types';

interface Stats {
  totalUsers: number;
  totalEntries: number;
  totalHistory: number;
  recentActivity: any[];
  users: any[];
  error?: string | null;
}

interface LogEntry {
  term: string;
  status: 'queued' | 'processing' | 'enriched' | 'completed' | 'error';
  message?: string;
}

const LANGUAGES_LIST: Language[] = ['German', 'Uzbek', 'English', 'Russian', 'Arabic'];

const AdminPanel: React.FC = () => {
  const [stats, setStats] = useState<Stats | null>(null);
  const [loading, setLoading] = useState(true);
  const [actionLoading, setActionLoading] = useState<string | null>(null);
  const [dbStatus, setDbStatus] = useState<'connected' | 'error' | 'checking'>('checking');

  // Bulk Inscription State
  const [bulkInput, setBulkInput] = useState('');
  const [sourceLang, setSourceLang] = useState<Language>('German');
  const [targetLang, setTargetLang] = useState<Language>('Uzbek');
  const [isProcessingBatch, setIsProcessingBatch] = useState(false);
  const [batchLogs, setBatchLogs] = useState<LogEntry[]>([]);
  const [currentProgress, setCurrentProgress] = useState(0);

  const loadStats = async () => {
    setLoading(true);
    setDbStatus('checking');

    // Perform a real health check
    const isAlive = await checkConnection();
    setDbStatus(isAlive ? 'connected' : 'error');

    const data = await fetchAdminStats();
    setStats(data as Stats);
    setLoading(false);
  };

  const handlePurgeCache = () => {
    setActionLoading('purge');
    triggerHaptic('heavy');
    setTimeout(() => {
      localStorage.removeItem('lexHistory');
      setActionLoading(null);
      alert("Local Archive Purged. System will resync on next reload.");
    }, 1500);
  };

  const handleGlobalSync = () => {
    setActionLoading('sync');
    triggerHaptic('success');
    loadStats().then(() => {
      setActionLoading(null);
    });
  };

  const processBulkInscription = async () => {
    const terms = bulkInput
      .split(/[\n,]+/)
      .map(t => t.trim())
      .filter(t => t.length > 0);

    if (terms.length === 0) return;

    setIsProcessingBatch(true);
    setCurrentProgress(0);
    setBatchLogs(terms.map(t => ({ term: t, status: 'queued' })));
    triggerHaptic('medium');

    for (let i = 0; i < terms.length; i++) {
      const term = terms[i];

      setBatchLogs(prev => prev.map((l, idx) => idx === i ? { ...l, status: 'processing' } : l));

      try {
        const coreEntry = await translateWordCore(term, sourceLang, targetLang);
        setBatchLogs(prev => prev.map((l, idx) => idx === i ? { ...l, status: 'enriched' } : l));
        const enrichment = await enrichLexicalEntry(coreEntry);
        const fullEntry = { ...coreEntry, ...enrichment };
        await saveGlobalEntry(fullEntry);
        setBatchLogs(prev => prev.map((l, idx) => idx === i ? { ...l, status: 'completed' } : l));
      } catch (err: any) {
        console.error(`Failed to inscribe ${term}:`, err);
        setBatchLogs(prev => prev.map((l, idx) => idx === i ? { ...l, status: 'error', message: err.message } : l));
      }

      setCurrentProgress(((i + 1) / terms.length) * 100);
    }

    setIsProcessingBatch(false);
    triggerHaptic('success');
    loadStats();
  };

