import { createClient } from '@supabase/supabase-js';
import { LexicalEntry, UserProfile, Language } from '../types';
import { CONFIG } from '../constants';

// Initialize with a fallback to prevent immediate crashes, but the service will report the error.
const supabaseUrl = CONFIG.SUPABASE_URL || 'https://placeholder-project.supabase.co';
const supabaseKey = CONFIG.SUPABASE_ANON_KEY || 'empty-key-placeholder';

export const supabase = createClient(supabaseUrl, supabaseKey);

const suggestionCache = new Map<string, string[]>();

const handleSupabaseError = (error: any, tableName: string) => {
  if (!CONFIG.SUPABASE_URL) return true;
  if (error?.code === 'PGRST204' || error?.code === 'PGRST205' || error?.status === 404 || error?.message?.includes('does not exist')) {
    console.warn(`Table [${tableName}] missing or unreachable.`);
    return true; 
  }
  if (error) console.error(`Supabase Error [${tableName}]:`, error);
  return false;
};

export async function checkConnection(): Promise<boolean> {
  if (!CONFIG.SUPABASE_URL) return false;
  try {
    const { error } = await supabase.from('lex_profiles').select('count', { count: 'exact', head: true }).limit(1);
    // If we get an error that is NOT "table not found", it might still be a valid connection (e.g., empty table)
    if (error && error.code === 'PGRST204') return true; 
    return !error;
  } catch {
    return false;
  }
}

export async function fetchAdminUsers() {
  if (!CONFIG.SUPABASE_URL) return [];
  try {
    const { data: profileData, error: profileError } = await supabase
      .from('lex_profiles')
      .select('username, telegram_id, updated_at')
      .order('updated_at', { ascending: false })
      .limit(50);

    if (profileError) {
      handleSupabaseError(profileError, 'lex_profiles');
      return [];
    }

    return (profileData || []).map(p => ({
      username: p.username,
      first_name: p.username || 'Scholar',
      created_at: p.updated_at
    }));
  } catch (err) {
    return [];
  }
}

export async function fetchAdminStats() {
  const defaultStats = { totalUsers: 0, totalEntries: 0, totalHistory: 0, recentActivity: [], users: [], error: null };

  if (!CONFIG.SUPABASE_URL) {
    return { ...defaultStats, error: 'SUPABASE_URL is missing. Please check your environment variables.' };
  }

  try {
    // We use allSettled to be resilient: if lex_user_history doesn't exist yet, we still want profile stats.
    const [profilesRes, entriesRes, historyRes, recentRes, userListRes] = await Promise.allSettled([
      supabase.from('lex_profiles').select('*', { count: 'exact', head: true }),
      supabase.from('lex_entries').select('*', { count: 'exact', head: true }),
      supabase.from('lex_user_history').select('*', { count: 'exact', head: true }),
      supabase.from('lex_entries').select('term, source_lang, target_lang, created_at').order('created_at', { ascending: false }).limit(10),
      fetchAdminUsers()
    ]);

    const stats: any = { ...defaultStats };
    let primaryError = null;

    if (profilesRes.status === 'fulfilled') {
      if (profilesRes.value.error) primaryError = profilesRes.value.error.message;
      else stats.totalUsers = profilesRes.value.count || 0;
    }

    if (entriesRes.status === 'fulfilled' && !entriesRes.value.error) {
      stats.totalEntries = entriesRes.value.count || 0;
    }

    if (historyRes.status === 'fulfilled' && !historyRes.value.error) {
      stats.totalHistory = historyRes.value.count || 0;
    }

    if (recentRes.status === 'fulfilled' && !recentRes.value.error) {
      stats.recentActivity = recentRes.value.data || [];
    }

    if (userListRes.status === 'fulfilled') {
      stats.users = userListRes.value;
    }

    if (primaryError) {
      stats.error = primaryError;
    } else if (profilesRes.status === 'rejected') {
      stats.error = "Connection rejected by the database host.";
    }

    return stats;
  } catch (err: any) {
    return { ...defaultStats, error: err.message || "Failed to retrieve archival statistics." };
  }
}

export async function fetchSuggestions(query: string, sourceLang: Language): Promise<string[]> {
  if (!CONFIG.SUPABASE_URL) return [];
  const cleanQuery = query.toLowerCase().trim();
  if (cleanQuery.length < 2) return [];

  const cacheKey = `${sourceLang}:${cleanQuery}`;
  if (suggestionCache.has(cacheKey)) return suggestionCache.get(cacheKey)!;

  try {
    const { data, error } = await supabase
      .from('lex_entries')
      .select('term')
      .eq('source_lang', sourceLang)
      .ilike('normalized_term', `${cleanQuery}%`)
      .limit(8);

    if (error) {
      handleSupabaseError(error, 'lex_entries');
      return [];
    }

    const results: string[] = Array.from(new Set((data?.map(d => (d as any).term) || []).filter((t): t is string => typeof t === 'string' && !!t)));
    suggestionCache.set(cacheKey, results);
    return results;
  } catch {
    return [];
  }
}

export async function fetchGlobalEntry(normalizedTerm: string, sourceLang: Language, targetLang: Language): Promise<LexicalEntry | null> {
  if (!CONFIG.SUPABASE_URL) return null;
  try {
    const { data, error } = await supabase
      .from('lex_entries')
      .select('entry_data')
      .eq('normalized_term', normalizedTerm)
      .eq('source_lang', sourceLang)
      .eq('target_lang', targetLang)
      .maybeSingle();

    if (error) return null;
    return (data?.entry_data as LexicalEntry) || null;
  } catch {
    return null;
  }
}

export async function saveGlobalEntry(entry: LexicalEntry) {
  if (!CONFIG.SUPABASE_URL) return;
  try {
    await supabase.from('lex_entries').upsert({
      term: entry.term,
      normalized_term: entry.normalizedTerm,
      source_lang: entry.sourceLang,
      target_lang: entry.targetLang,
      entry_data: entry,
      created_at: new Date().toISOString()
    }, { onConflict: 'normalized_term, source_lang, target_lang' });
  } catch {}
}

